// src/context/AuthContext.js
import React, { createContext, useContext, useEffect, useState } from "react";
import axios from "axios";

const AuthContext = createContext();

export function AuthProvider({ children }) {
  // Estado global de usuário: obtém de localStorage uma vez ao montar
  const [user, setUser] = useState(() => {
    const role = localStorage.getItem("role");
    const token = localStorage.getItem("token");
    const id = localStorage.getItem("id");
    const nome = localStorage.getItem("nome");

    return role && token
      ? { role, token, id: id ? parseInt(id) : null, nome }
      : null;
  });

  // Sempre que o "user" muda, ajusta header do axios
  useEffect(() => {
    if (user?.token) {
      axios.defaults.headers.common["Authorization"] = `Bearer ${user.token}`;
    } else {
      delete axios.defaults.headers.common["Authorization"];
    }
  }, [user]);

  // Função para login: espera receber { role, token, id, usuario }
  function login({ role, token, id, usuario }) {
    // Configura o estado local
    setUser({ role, token, id, nome: usuario });

    // Salva no localStorage
    localStorage.setItem("role", role);
    localStorage.setItem("token", token);
    localStorage.setItem("id", id);
    localStorage.setItem("nome", usuario);

    // Ajusta header imediatamente (o useEffect cuidará também)
    axios.defaults.headers.common["Authorization"] = `Bearer ${token}`;
  }

  // Função para logout
  function logout() {
    setUser(null);
    localStorage.removeItem("role");
    localStorage.removeItem("token");
    localStorage.removeItem("id");
    localStorage.removeItem("nome");
    delete axios.defaults.headers.common["Authorization"];
  }

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

// Hook para consumir contexto
export function useAuth() {
  return useContext(AuthContext);
}
